module RefModule (
    input clk,
    input shift_enable,
    input load_enable,
    input [7:0] data_in,
    output [7:0] data_out );reg [7:0] obf_register;

always @(posedge clk) begin
    if (load_enable)
        obf_register <= data_in;
    else if (shift_enable)
        obf_register <= {obf_register[6:0], 1'b0};
end

assign data_out = obf_register;

endmodule
